// Parsear payload de WhatsApp Business API (Meta)
const body = $input.first().json.body;

// Verificar que es un mensaje válido
const entry = body?.entry?.[0];
const changes = entry?.changes?.[0];
const value = changes?.value;
const messages = value?.messages;

if (!messages || messages.length === 0) {
  // Es un webhook de verificación o sin mensajes
  return [{ json: { skip: true } }];
}

const message = messages[0];
const phone = message.from; // número del remitente
const messageType = message.type; // text, audio, image
const channelMessageId = message.id;

let rawText = null;
let rawContent = null;

if (messageType === 'text') {
  rawText = message.text?.body || '';
} else if (messageType === 'audio') {
  rawContent = message.audio?.id; // ID del media en WhatsApp
} else if (messageType === 'image') {
  rawContent = message.image?.id; // ID del media en WhatsApp
}

return [{
  json: {
    phone,
    messageType,
    rawText,
    rawContent,
    channelMessageId,
    skip: messageType !== 'text' // este workflow solo maneja texto
  }
}];

