// Parsear respuesta de la IA y decidir qué hacer
const iaResponse = $input.first().json;
const rawContent = iaResponse.choices?.[0]?.message?.content || '{}';

let extracted;
try {
  extracted = JSON.parse(rawContent);
} catch(e) {
  extracted = { confidence_score: 0, confidence_reason: 'Error parsing IA response' };
}

const userId = $('Buscar/Crear Usuario').first().json.id;
const messageId = $('Guardar Mensaje').first().json.id;
const rawText = $('Parsear Payload WhatsApp').first().json.rawText;
const phone = $('Parsear Payload WhatsApp').first().json.phone;

const confidence = extracted.confidence_score || 0;
let expenseStatus = 'error';
let messageStatus = 'error';
let replyText = '';

if (confidence >= 0.85 && extracted.amount) {
  expenseStatus = 'confirmed';
  messageStatus = 'processed';
  replyText = `✅ Registré L ${Number(extracted.amount).toLocaleString('es-HN')} en ${extracted.category_guess || 'Otros'}.`;
} else if (confidence >= 0.50 && extracted.amount) {
  expenseStatus = 'pending';
  messageStatus = 'processed';
  replyText = `⚠️ Registré L ${Number(extracted.amount).toLocaleString('es-HN')} (pendiente de revisión). Verifica en la app.`;
} else if (extracted.amount) {
  expenseStatus = 'incomplete';
  messageStatus = 'error';
  replyText = `❓ Registré L ${Number(extracted.amount).toLocaleString('es-HN')} pero faltaron datos. Completa en la app.`;
} else {
  expenseStatus = 'error';
  messageStatus = 'error';
  replyText = `❌ No pude interpretar tu gasto. Escribe: "Gasté [monto] en [descripción]" o usa la app para registrar manualmente.`;
}

return [{
  json: {
    userId, messageId, phone,
    extracted,
    expenseStatus,
    messageStatus,
    replyText,
    shouldCreateExpense: !!extracted.amount
  }
}];
